from functools import wraps

# Step 1: A simple decorator (no arguments)
def shout(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        result = func(*args, **kwargs)
        return result.upper() if isinstance(result, str) else result
    return wrapper

@shout
def greet(name):
    """Return a greeting message."""
    return f"hello, {name}"

print(greet("Aarav"))          # HELLO, AARAV
print(f"Name: {greet.__name__}") # greet (preserved by @wraps)
print(f"Doc: {greet.__doc__}")   # Return a greeting message.

# Step 2: Show that @ is syntactic sugar
def greet2(name):
    return f"hello, {name}"

greet2 = shout(greet2)  # Same as @shout
print(greet2("Priya"))  # HELLO, PRIYA

# Step 3: Decorator that modifies behavior
def log_calls(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        print(f"  -> Calling {func.__name__}({args}, {kwargs})")
        result = func(*args, **kwargs)
        print(f"  <- {func.__name__} returned {result}")
        return result
    return wrapper

@log_calls
def add(a, b):
    return a + b

result = add(3, 7)

import time
from functools import wraps

# Timer decorator
def timer(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        start = time.perf_counter()
        result = func(*args, **kwargs)
        elapsed = time.perf_counter() - start
        print(f"  {func.__name__}: {elapsed:.6f}s")
        return result
    return wrapper

# Memoize decorator
def memoize(func):
    cache = {}
    @wraps(func)
    def wrapper(*args):
        if args not in cache:
            cache[args] = func(*args)
        return cache[args]
    wrapper.cache = cache  # Expose cache for inspection
    return wrapper

# Without memoize: slow recursive fibonacci
@timer
def fib_slow(n):
    if n < 2:
        return n
    return fib_slow.__wrapped__(n-1) + fib_slow.__wrapped__(n-2)  # unwrapped for timing

# Simpler: memoized fibonacci
@memoize
def fib_fast(n):
    if n < 2:
        return n
    return fib_fast(n-1) + fib_fast(n-2)

print("Memoized fibonacci:")
start = time.perf_counter()
result = fib_fast(30)
print(f"  fib_fast(30) = {result}")
print(f"  Time: {time.perf_counter() - start:.6f}s")
print(f"  Cache size: {len(fib_fast.cache)}")

from functools import wraps

# Decorator that takes arguments
def repeat(times):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            for i in range(times):
                result = func(*args, **kwargs)
            return result
        return wrapper
    return decorator

def tag(tag_name):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            result = func(*args, **kwargs)
            return f"<{tag_name}>{result}</{tag_name}>"
        return wrapper
    return decorator

# Using decorator with arguments
@repeat(times=3)
def say_hi(name):
    print(f"  Hi, {name}!")
    return f"Hi, {name}!"

print("repeat(3):")
say_hi("Aarav")

# Stacking decorators (applied bottom to top)
@tag("b")
@tag("i")
def greet(name):
    return f"Hello, {name}"

print(f"\nStacked: {greet('Priya')}")
# Equivalent to: greet = tag('b')(tag('i')(greet))
# Inner: <i>Hello, Priya</i>
# Outer: <b><i>Hello, Priya</i></b>

from functools import wraps

# Class-based decorator with state
class CountCalls:
    def __init__(self, func):
        wraps(func)(self)
        self.func = func
        self.count = 0

    def __call__(self, *args, **kwargs):
        self.count += 1
        return self.func(*args, **kwargs)

    def reset(self):
        self.count = 0

@CountCalls
def add(a, b):
    return a + b

print(add(1, 2))        # 3
print(add(3, 4))        # 7
print(add(5, 6))        # 11
print(f"Calls: {add.count}")  # 3
add.reset()
print(f"After reset: {add.count}")  # 0

# @property decorator revisited
class Temperature:
    def __init__(self, celsius):
        self._celsius = celsius

    @property
    def celsius(self):
        return self._celsius

    @celsius.setter
    def celsius(self, value):
        if value < -273.15:
            raise ValueError("Below absolute zero!")
        self._celsius = value

    @property
    def fahrenheit(self):
        return self._celsius * 9/5 + 32

t = Temperature(100)
print(f"\n{t.celsius}C = {t.fahrenheit}F")
t.celsius = 0
print(f"{t.celsius}C = {t.fahrenheit}F")

